def zipkin_span_decorate(*args_out, **kw_out):
    def decorate(f):
        def inner(*args, **kw):
            with zipkin_span(*args_out, **kw_out):
                return f(*args, **kw)
        return inner
    return decorate

@zipkin_span_decorate(service_name='webapp', span_name='do_stuff')
def do_stuff():
    headers = create_http_headers_for_new_span()
    requests.get('http://localhost:6000/service1/', headers=headers)
    return 'OK'
```
